insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('retrievalevaluation', 'Retrieval evaluation', '', '', ARRAY['retrieval eval']::text[], 'Core', 'Measuring whether the documents you pulled actually contain the answer to the question.', 'Fact-checking the articles your research assistant grabbed — did they grab the right ones?', 'You ask a RAG system "What does the company spend on R&D?" and it pulls five documents. Three are about marketing, two are about finance. Only the finance ones help — that''s a retrieval failure.', '[{"text":"Part of the RAG pipeline."},{"text":"Partner metric for generation quality."}]'::jsonb, 'Retrieval is where RAG lives or dies. You measure it with metrics like precision (fraction of retrieved docs that were relevant), recall (fraction of relevant docs that were actually retrieved), and MRR (mean reciprocal rank — how high up was the first good one). Bad retrieval kills everything downstream, no matter how good your language model is.', 'If your RAG system gives wrong answers, check retrieval first — it''s often the culprit, and fixing it beats retraining the model.', 'Evaluate retrieval separately from generation using metrics like precision@k, recall@k, NDCG, and MRR against gold documents.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('scoringfunction', 'Scoring function', '', '', ARRAY['ranking function','relevance score']::text[], 'Core', 'A formula that ranks documents by how likely they are to answer the question.', 'Like a bouncer at a bar — you ask "Is this person relevant?" and the function returns a score instead of yes/no.', 'A BM25 scoring function looks at word frequency and document length. A learned ranker might use a neural network trained on click data. Both output a number — higher means "more relevant."', '[{"text":"Used in reranking pipelines."}]'::jsonb, 'Scoring functions sit between retrieval and ranking. Simple ones (BM25, TF-IDF) are keyword-based and fast. Learned ones (LambdaMART, neural rankers) are expensive but accurate. The catch: your training data shapes what "relevant" means, so garbage labels in training produce garbage scores at inference.', 'A better scoring function can mean the difference between users finding answers on page one vs. page five.', 'Implement as a function(query, doc) → score, where score is a real number. Train on relevance labels if building a learned ranker.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('referenceanswer', 'Reference answer', '', '', ARRAY['gold answer','gold reference']::text[], 'Core', 'The correct answer to a question, written by a human, that you use to grade automated responses.', 'The answer key to a test — you check whether students got it right by comparing to this.', 'For "What is the capital of France?" the reference answer is "Paris." If your model says "Paris" or "The capital of France is Paris," both grade as correct against this reference.', '[{"text":"Used in evals with baselines."}]'::jsonb, 'Reference answers are expensive — humans have to write them. Some systems use multiple references (Paris, Île-de-France) to allow variation. The danger: a good answer that differs from the reference gets marked wrong, so your eval underestimates model quality. This is why reference-free evaluation exists.', 'You need reference answers to grade at scale, but they''re a bottleneck. Budget time to create them.', 'Store as gold annotations. Use fuzzy matching or embedding similarity to accept minor paraphrases.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('referencefreeeval', 'Reference-free evaluation', '', '', ARRAY['llm-judge','self-evaluation']::text[], 'Rising', 'Using a strong language model to grade answers without comparing them to a human-written reference.', 'Instead of an answer key, you ask an expert teacher to grade the essay directly.', 'Asking GPT-4 "Is this response correct, helpful, and complete?" and getting a score back, instead of comparing to a stored reference answer.', '[{"text":"Used when ground truth is hard to define."}]'::jsonb, 'LLM-as-judge is fast and scalable but introduces new failure modes. The grading model can be fooled by confident-sounding but wrong answers. Cultural bias in the judge affects scores. It''s useful for signals like tone and coherence, less reliable for factual correctness. You still want some human spot-checks.', 'Faster and cheaper than human annotation, but not fully trustworthy — use as a filter, not ground truth.', 'Call your judge LLM with a prompt asking for a score(1-10) plus reasoning. Parse the score, log the reasoning for auditing.', 'Evaluation & quality', 60, ARRAY['seed','evaluation-quality']::text[]),
  ('selfconsistencycheck', 'Self-consistency check', '', '', ARRAY['consistency checking','ensemble agreement']::text[], 'Rising', 'Running the same prompt multiple times and checking whether the model gives the same answer each time.', 'Asking a friend the same question three times and seeing if they answer consistently.', 'You ask a model "Is 17 prime?" ten times with temperature 1.0. If it says "yes" eight times and "no" twice, that''s concerning — the true answer should be consistent.', '[{"text":"Related pattern for confidence estimation."}]'::jsonb, 'Self-consistency uses the model to grade itself. High variance across runs suggests either ambiguous inputs or hallucination. The catch: multiple outputs that agree can all be wrong if the model is confidently biased. You''re measuring consistency, not correctness.', 'A cheap signal that something might be wrong, but not a sign that something is right.', 'Run k times, check whether outputs match. Use embedding similarity for fuzzy matching on non-binary answers.', 'Evaluation & quality', 60, ARRAY['seed','evaluation-quality']::text[]),
  ('majorityvoting', 'Majority voting', '', '', ARRAY['ensemble voting','plurality']::text[], 'Core', 'Asking multiple models or multiple runs of the same model and going with the most common answer.', 'A jury voting on guilt — whichever verdict gets the most votes wins.', 'You ask five different models the same question. Three say yes, two say no. You take "yes" as the answer.', '[{"text":"Ensemble technique for robustness."}]'::jsonb, 'Majority voting works because diverse models often fail in different ways. But it''s expensive — you pay for five models instead of one. It also assumes the models are somewhat independent; if they''re all fine-tuned on the same data, their errors correlate and voting doesn''t help. Edge case: tie votes.', 'Valuable for high-stakes decisions but has a cost — use only where accuracy matters enough to pay the price.', 'Collect outputs from k models, count votes, return mode. Handle ties by picking alphabetically or using a tiebreaker model.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('ensembleeval', 'Ensemble evaluation', '', '', ARRAY['voting evaluation','multi-judge']::text[], 'Rising', 'Using multiple evaluators (models or humans) to grade the same output and averaging their scores.', 'Having three teachers grade the same essay and averaging the scores.', 'Running Claude, GPT-4, and Llama against your outputs and averaging their ratings of relevance from 1–10.', '[{"text":"Hardens eval reliability."}]'::jsonb, 'Ensemble eval reduces bias from any single grader. But it''s expensive and sometimes the models agree because they''re trained on similar data. For critical applications, combining automated scoring with human spot-checks is better than either alone.', 'More reliable than single-judge evals but also more expensive. Use for milestones, not daily testing.', 'Call multiple eval models, collect scores, return mean and std. Log disagreements for audit trails.', 'Evaluation & quality', 60, ARRAY['seed','evaluation-quality']::text[]),
  ('holdouteval', 'Holdout eval', '', '', ARRAY['holdout evaluation','train-test split']::text[], 'Core', 'A dataset of examples you set aside before training and only use to evaluate the final model.', 'Sealing an envelope with the correct answers and only opening it after you''ve written your essay.', 'You have 1000 examples. You train on 800, validate on 100, and holdout 100 for final testing. You never tune your model on the holdout set.', '[{"text":"Foundation of honest evaluation."}]'::jsonb, 'Holdout evals protect you from overfitting — you can''t cheat on examples you never saw during development. The size matters: too small and noise dominates, too large and you lose training data. Best practice: don''t peek at holdout results during development, only at the end.', 'Non-negotiable for credible results. It''s the difference between a real benchmark and a cherry-picked demo.', 'Create before any model training. Version control the split. Never use for hyperparameter tuning.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('offlineeval', 'Offline evaluation', '', '', ARRAY['batch evaluation','pre-deployment']::text[], 'Core', 'Testing your system against a fixed dataset of past examples, not real users.', 'A flight simulator — you practice on the ground before flying.', 'Running your retrieval system against 1000 Q&A pairs before deploying it to production.', '[{"text":"Paired with online evaluation."},{"text":"Baseline metric before launch."}]'::jsonb, 'Offline eval is fast and cheap but can miss real-world failures. Users ask questions offline eval never saw. Traffic patterns, edge cases, and adversarial inputs appear only once you''re live. This is why online evaluation exists.', 'Necessary but not sufficient. Use to gate deployment, but plan for online eval post-launch.', 'Batch process against fixed examples. Log results, compute aggregate metrics, generate reports.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('onlineeval', 'Online evaluation', '', '', ARRAY['live eval','production evaluation']::text[], 'Core', 'Measuring how your system performs on real user traffic after it''s deployed.', 'A test drive with real traffic, not an empty parking lot.', 'After deploying a new ranking model, you measure how often users click on the top result or use the search again immediately.', '[{"text":"Complements offline evaluation."}]'::jsonb, 'Online eval sees real behavior but it''s slow and messy. Users don''t always click the right result, and clicks can mean "interesting" instead of "relevant." You need statistical rigor to tell signal from noise. And online eval is asymmetric — you can''t easily test bad ideas without harming users.', 'Critical for real product decisions. Offline evals get you 80% of the way, but online results tell you whether users actually care.', 'Instrument logging, run A/B tests, compute metrics on real traffic, implement guardrails to catch regressions.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('shadowtesting', 'Shadow testing', '', '', ARRAY['shadow deployment','shadow mode']::text[], 'Rising', 'Running a new model in parallel on real traffic without showing results to users, just to see how it would perform.', 'A stunt double doing the same scene as the actor — you see if they''d succeed without affecting the movie.', 'You deploy a new ranking model that runs on every search query but doesn''t affect results. You log how it would rank things, then later compare against what the old model did.', '[{"text":"Precursor to canary evaluation."}]'::jsonb, 'Shadow testing lets you evaluate on 100% of real traffic without risk. The catch: users don''t interact with shadow results, so you can''t measure engagement. And running both models costs resources. It''s best for measuring offline metrics (relevance, retrieval quality) that don''t need user interaction.', 'Safe way to test radical changes. Cost-benefit depends on your traffic and how expensive running two models is.', 'Run both models, log both sets of results, compute metrics on shadow results post-hoc. Skip user interaction data.', 'Evaluation & quality', 60, ARRAY['seed','evaluation-quality']::text[]),
  ('canaryeval', 'Canary evaluation', '', '', ARRAY['canary rollout','gradual rollout']::text[], 'Rising', 'Rolling out a change to a small fraction of real users and monitoring for problems before going to 100%.', 'A canary in a coal mine — send in a small probe first to check for danger.', 'You deploy a new model to 5% of search traffic. If latency stays good and click-through rate doesn''t drop, roll to 10%. If anything breaks, rollback immediately.', '[{"text":"Production-safe eval pattern."}]'::jsonb, 'Canary deployments reduce risk but require automated monitoring and quick rollback. You need alarms for latency, errors, and engagement metrics. The cost of rollback must be lower than the cost of breaking all users. And you need enough traffic in the canary to detect real problems (5% might miss low-frequency bugs).', 'Standard practice for high-stakes changes. Non-negotiable for production services.', 'Implement traffic splitting, automated metric collection, and rollback triggers. Monitor continuously.', 'Evaluation & quality', 60, ARRAY['seed','evaluation-quality']::text[]),
  ('evaldrivendev', 'Eval-driven development', '', '', ARRAY['metric-driven','test-first']::text[], 'Rising', 'Writing evals first, before you build the feature, then iterating to pass them.', 'Test-driven development for language models — write the test, then write the code.', 'You need a system to summarize documents. You write 50 examples with gold summaries and grade them on ROUGE score. Then you iterate on prompts until your ROUGE improves.', '[{"text":"Philosophical approach to quality."}]'::jsonb, 'Eval-driven development forces clarity about what "done" means. It makes progress visible and prevents shipping half-baked features. The danger: optimizing the metric instead of the real problem. A high ROUGE score doesn''t guarantee users like the summary.', 'Speeds up iteration and keeps teams aligned. Requires discipline to not game the metrics.', 'Write evals in a CI pipeline. Gate merges on eval improvements. Track score history.', 'Evaluation & quality', 60, ARRAY['seed','evaluation-quality']::text[]),
  ('coverage', 'Coverage', '', '', ARRAY['scenario coverage','domain coverage']::text[], 'Core', 'The fraction of real-world cases your evaluation set actually represents.', 'Checking whether your test suite covers all code branches.', 'Your retrieval eval set has 100 questions, all from tech documentation. But users ask health questions 20% of the time. Your eval coverage for health is 0%.', '[{"text":"Honest evaluation requires it."}]'::jsonb, 'Low coverage means you''re not testing real failure modes. If your eval set is too narrow, a model can look good in eval but fail in production. Measuring coverage is hard — you need a taxonomy of case types and counts for each. And covering all types means your eval set grows quickly.', 'Uneven coverage is why models break on edge cases. Audit your eval set to make sure it represents your traffic.', 'Tag eval examples by domain/type. Report coverage stats. Flag low-frequency types.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('edgecasetesting', 'Edge case testing', '', '', ARRAY['corner cases','boundary testing']::text[], 'Core', 'Deliberately testing unusual, rare, or boundary inputs that your main eval might miss.', 'Testing a bridge not just with normal traffic but with an overloaded truck on it.', 'Your chatbot eval includes normal questions, but you add edge cases like "How do you spell your name?", empty queries, and profanity.', '[{"text":"Robustness requires it."}]'::jsonb, 'Edge cases break systems in predictable ways. Models hallucinate on out-of-distribution inputs. Retrievers fail on ambiguous queries. Building a comprehensive edge case set is tedious but worth it — a single broken edge case in production looks bad. Organize by failure mode: ambiguity, adversarial inputs, off-topic, truncation.', 'One bad edge case in production kills trust. Invest time here.', 'Maintain a curated set of edge cases. Add to it every time you find a production bug.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('stresstesting', 'Stress testing', '', '', ARRAY['load testing','scalability']::text[], 'Core', 'Pushing your system to its limits with extreme volume, latency, or complexity to find breaking points.', 'A car crash test — you intentionally break it to see where it fails.', 'You load-test your inference server by sending 100,000 queries per second and monitoring when latency explodes or requests error.', '[{"text":"Infrastructure readiness."}]'::jsonb, 'Stress tests reveal infrastructure limits, not model quality. You find that your GPU runs out of memory at 500 concurrent requests, or your database hits its connection pool. These are predictable failures once you know the limit. The goal: know your limits before users find them.', 'Essential before scaling. Know where you''ll break before it matters.', 'Use load-testing tools (locust, k6, jmeter). Gradually increase load, log when metrics degrade, measure breaking point.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('adversarialeval', 'Adversarial evaluation', '', '', ARRAY['jailbreak testing','attack testing']::text[], 'Rising', 'Testing whether your system can be tricked or broken by intentionally malicious or tricky inputs.', 'A security audit where you try to hack your own system.', 'You ask a safety-tuned model "How do I make a bomb?" in ten different ways to see which phrasing bypasses the safety filter.', '[{"text":"Safety evaluation."}]'::jsonb, 'Adversarial eval separates models that are robust from models that look good until someone attacks them. Human red-teamers are expensive but creative. Automated attacks (prompt injection, token smuggling) are cheaper but sometimes miss real vulnerabilities. Most models have adversarial inputs that break them; the question is how easy they are to find.', 'Safety-critical applications need this. It''s not paranoia if it''s a real risk.', 'Maintain a library of adversarial prompts. Test against them in CI. Automate where possible, humans for creativity.', 'Evaluation & quality', 60, ARRAY['seed','evaluation-quality']::text[]),
  ('robustnesstest', 'Robustness testing', '', '', ARRAY['perturbation testing','invariance']::text[], 'Rising', 'Systematically changing inputs slightly (typos, paraphrases, noise) to see whether outputs stay consistent.', 'A wine tasting where you test whether the wine''s quality is consistent even when slightly off.', 'You take your test set and add typos, reorder sentences, and change synonyms. If your model''s answers change drastically, it''s not robust.', '[{"text":"Generalization metric."}]'::jsonb, 'Robustness testing catches models that are brittle — good on the exact examples they''ve seen, bad on anything slightly different. It''s cheaper than adversarial eval but less thorough. You can automate it by programmatically perturbing your test set.', 'Tell you whether improvements are real or just overfitting to your eval set.', 'For each example, generate perturbations (typos, synonym replacements, paraphrases). Check if outputs match via embedding similarity.', 'Evaluation & quality', 60, ARRAY['seed','evaluation-quality']::text[]),
  ('capabilityeval', 'Capability evaluation', '', '', ARRAY['skills testing','ability measure']::text[], 'Core', 'Testing whether a model can perform a specific skill (math, code, reasoning) at all, regardless of perfect execution.', 'A driver''s test where you just check whether someone can parallel park, not how perfectly.', 'Does the model know how to do chain-of-thought reasoning on math problems? You ask a few hard math questions and see if it attempts reasoning steps.', '[{"text":"Precursor to detailed evaluation."}]'::jsonb, 'Capability eval answers "can this model do the thing?" Benchmark eval answers "how well?" Capabilities emerge unpredictably as models scale, so capability eval is how researchers discover new abilities. The catch: a model might have the capability but fail due to prompting, temperature settings, or just bad luck on the sample.', 'Tells you what to expect from a model before detailed benchmarking.', 'Write tests for each capability. Use simple examples first. Track emergence curves as models scale.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('redteameval', 'Red-team evaluation', '', '', ARRAY['vulnerability testing','human attack']::text[], 'Rising', 'Having human experts intentionally try to break your system to find real-world vulnerabilities before users find them.', 'A professional locksmith trying to pick your locks to show you weaknesses.', 'A safety-specialized contractor generates 100 prompts designed to make a language model refuse to help or produce harmful content, testing your safety guardrails.', '[{"text":"Serious vulnerability hunting."}]'::jsonb, 'Red-teaming is expensive but produces creative attacks. Humans find vulnerabilities that automated tests miss. The downside: red-teaming doesn''t scale, takes weeks, and teams can have blind spots. Best practice: combine human red-teaming with automated testing.', 'Budget for it before launch, especially on safety-critical features.', 'Partner with red-team experts. Log and triage findings. Iterate on mitigations.', 'Evaluation & quality', 60, ARRAY['seed','evaluation-quality']::text[]),
  ('rewardmodeleval', 'Reward model eval', '', '', ARRAY['preference eval','ranking measurement']::text[], 'Rising', 'Testing whether your preference model or reward model correctly ranks good outputs above bad ones.', 'Checking whether a referee''s judgment matches actual game rules.', 'You have pairs of responses (good, bad). Your reward model should score the good one higher. You measure what fraction it gets right.', '[{"text":"Part of RLHF pipelines."}]'::jsonb, 'Reward model evals check a different signal than generation evals. A reward model might rank A > B while a user would choose B > A. Reward models inherit biases from their training data — if trained on assistant-friendly feedback, they score conservative outputs high even when users want bold ones. This is why some teams use preference data directly instead of training an intermediate reward model.', 'A biased reward model breaks your whole RLHF pipeline. Test it separately.', 'Collect preference pairs. Measure accuracy, Kendall tau, or AUC. Stratify by example type.', 'Evaluation & quality', 60, ARRAY['seed','evaluation-quality']::text[]),
  ('distributionshift', 'Distribution shift', '', '', ARRAY['data drift','covariate shift']::text[], 'Core', 'When your model''s test data comes from a different distribution than what it''ll see in production.', 'Training a classifier on daytime photos, then using it on nighttime photos.', 'Your NER model is trained on news articles. You deploy it to social media. Tweets are informal, have slang, use emojis — the distribution shifted. Performance drops.', '[{"text":"Real-world problem."}]'::jsonb, 'Distribution shift is subtle because performance on old data stays good — you don''t notice until production fails. Types include covariate shift (input distribution changes), label shift (class distribution changes), and concept drift (the relationship itself changes). Some shifts are fixable (retraining), others require architectural changes.', 'Expect model performance to degrade post-launch. Monitor for it. Plan retraining cycles.', 'Collect examples from production. Compare feature distributions to training. Set up drift detection.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('ooddetection', 'Out-of-distribution', '', '', ARRAY['ood','anomaly detection']::text[], 'Core', 'Input examples that don''t match the distribution your model saw during training.', 'Showing someone a cat photo when they''ve only ever seen dogs.', 'Your model is trained on English news. A user asks in Spanish. The Spanish input is out-of-distribution.', '[{"text":"Opposite of in-distribution."}]'::jsonb, 'OOD inputs cause poor model behavior because the model is extrapolating past its training data. Some models are robust (they say "I don''t know"), others hallucinate confidently. Detecting OOD without ground truth is hard — you can''t just check if the input looks weird because the model''s embedding space might not preserve "weirdness" in a useful way.', 'Plan for OOD gracefully. Don''t let users hit it without warning.', 'Use uncertainty estimates, entropy, or embedding distance to detect OOD. Fallback to a simpler system.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('indistribution', 'In-distribution', '', '', ARRAY['on-distribution','id examples']::text[], 'Core', 'Input examples that match the distribution your model was trained on.', 'Showing a dog-trained model another dog photo.', 'If your model is trained on Wikipedia articles, another Wikipedia article is in-distribution. A tweet is not.', '[{"text":"Counterpart to out-of-distribution."}]'::jsonb, 'In-distribution examples get good model performance, but "distribution" is fuzzy. Is a dog photo taken at night in-distribution for a model trained on daytime photos? Probably partly. You can measure distributional similarity with Jensen-Shannon divergence or other metrics, but there''s no sharp threshold. The practical question: does my model perform well on this type of input?', 'Easier to predict model success. Challenges appear at distribution boundaries.', 'Profile your training data distribution. Check new examples against it. Set an acceptance threshold.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('evalleakage', 'Eval leakage', '', '', ARRAY['test contamination','leakage detection']::text[], 'Core', 'When examples from your test or eval set accidentally end up in training data, inflating your metrics.', 'Reading the answer key before writing your essay, then claiming you got it right.', 'You train a model on a dataset that (unnoticed) includes 5% of your eval set. Your eval scores look great, but it''s because you''ve seen those examples before.', '[{"text":"Evaluation integrity."}]'::jsonb, 'Eval leakage is insidious because it''s hard to catch. It happens when combining multiple datasets, scraping web data, or data pipeline mistakes. It inflates metrics and makes models look better than they are. Once you deploy, real-world performance drops and you wonder why your eval didn''t predict it.', 'A broken eval is worse than no eval. Always check for leakage before trusting results.', 'Deduplicate across train/val/test. Use hashing to detect near-duplicates. Never train on eval data.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('contaminationcheck', 'Contamination check', '', '', ARRAY['decontamination','overlap check']::text[], 'Core', 'Scanning your training data for examples that appear in public benchmarks, which would invalidate your results.', 'Checking whether your school essay was plagiarized from Wikipedia.', 'You train a model on Common Crawl. Later you discover your training data includes 1% of the MMLU benchmark. Your MMLU score is no longer credible.', '[{"text":"Integrity check."}]'::jsonb, 'Large-scale training makes contamination easy — you''re training on billions of tokens and those tokens came from the internet, which includes benchmarks. Major labs now report contamination percentages. Fixing it requires deduplicating against benchmarks (expensive) or using evaluation code in training data and being honest about it (rare).', 'Benchmark scores without contamination analysis are meaningless. Demand evidence of decontamination.', 'Download public benchmarks. Deduplicate training data against them using hashing and embedding similarity.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('statsignificance', 'Statistical significance', '', '', ARRAY['p-value','hypothesis test']::text[], 'Core', 'Whether a difference in metrics is real or just random variation.', 'Checking whether a coin is unfair by flipping it many times — one heads isn''t proof, but 100 heads in 100 flips is.', 'Model A scores 85% and Model B scores 86% on your test set. Is B really better, or is that just noise? You run a significance test.', '[{"text":"Rigor in evaluation."}]'::jsonb, 'Significance tests tell you whether observed differences are likely under the null hypothesis (they''re the same). Low p-value means unlikely under null, so you reject it. The catch: significance depends on sample size (large N makes tiny differences significant) and the test you choose. And significance isn''t the same as importance — a tiny statistically significant improvement might not matter.', 'Don''t ship based on 1% improvements. Demand both significance and practical importance.', 'Use paired t-tests for comparisons on the same examples, Mann-Whitney for unpaired. Report p-values and confidence intervals.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('confidenceinterval', 'Confidence interval', '', '', ARRAY['ci','error bars']::text[], 'Core', 'A range around your metric that''s likely to contain the true value, given your sample.', 'A fishing net that you''re 95% sure contains the fish.', 'Your model scores 85% accuracy on 1000 examples. The 95% CI is [82%, 88%]. You''re saying: if I ran this experiment again, the true accuracy is probably between 82% and 88%.', '[{"text":"Statistical reporting."}]'::jsonb, 'Confidence intervals are more informative than point estimates. A metric of 85% ± 3% tells you the result is stable. A metric of 85% ± 10% is wobbly and might change on a different sample. The width depends on sample size and variance. Smaller sample = wider interval.', 'Report CIs alongside metrics. They show how confident you should be.', 'Compute from bootstrap resampling or analytical formulas. Report 95% or 90% CIs.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('modelvariance', 'Variance', '', '', ARRAY['eval variance','measurement variability']::text[], 'Core', 'How much your metric bounces around when you measure the same thing multiple times.', 'A scale that says your weight is different every time you step on it — high variance, not trustworthy.', 'You run your eval set ten times. You get scores: 84%, 86%, 85%, 87%, 84%, 85%, 86%, 84%, 85%, 85%. High variance would be 70%, 95%, 78%, 92%.', '[{"text":"Part of eval quality assessment."}]'::jsonb, 'Variance comes from model stochasticity (temperature, sampling), eval set size, and randomness in training. High variance evals are noisy — you can''t trust small improvements. Reducing variance means using larger eval sets, lowering temperature, or averaging across runs. The tradeoff: low variance costs more compute.', 'If your eval metric bounces around, you can''t tell if changes actually help.', 'Measure by running k times. Compute std and CV. If high, use larger sample or average runs.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('noisefloor', 'Noise floor', '', '', ARRAY['baseline variance','detection limit']::text[], 'Core', 'The minimum detectable change in your metric, below which differences are just noise.', 'Audio equipment with background hum at 30dB — you can''t hear signals quieter than that.', 'Your eval metric is 85% ± 5% (std 5%). The noise floor is around 5%. Changes smaller than that are invisible in the noise.', '[{"text":"Separates signal from noise."}]'::jsonb, 'Knowing your noise floor is critical. If you can only detect 2% changes, a 1% improvement is meaningless even if it''s technically better. Lowering the noise floor requires larger eval sets (expensive) or lower-variance metrics (hard to design). Many papers ignore noise floor and claim credit for improvements smaller than it.', 'Only trust improvements larger than your noise floor. Anything smaller is statistical illusion.', 'Compute from your eval variance. Report it alongside metrics. Flag claimed improvements smaller than it.', 'Evaluation & quality', 80, ARRAY['seed','evaluation-quality']::text[]),
  ('serving', 'Serving', '', '', ARRAY['inference server','model deployment']::text[], 'Core', 'Running a trained model in production to answer real user queries.', 'Opening a restaurant after months of cooking in your home kitchen.', 'You train a summarization model and deploy it on AWS behind an API so users can call it.', '[{"text":"Where models go to work."}]'::jsonb, 'Serving is where the rubber meets the road. Training a model is one problem; serving it to millions of users on low latency with high reliability is another. You need caching, batching, load balancing, and fallbacks. A model that works in training can be slow, memory-hungry, or unreliable at scale. Most production failures are in serving, not modeling.', 'Serving costs matter. A slow model is a bad model.', 'Use optimized frameworks (vLLM, TensorRT). Profile latency and throughput. Implement monitoring and rollback.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('timetofirsttoken', 'Time to first token', '', '', ARRAY['ttft','first token latency']::text[], 'Core', 'How long between sending a request and receiving the first output token.', 'The delay between asking a question and hearing the first word of the answer.', 'You send a request to a language model. After 500ms, you get the first token. TTFT = 500ms.', '[{"text":"Key latency metric."}]'::jsonb, 'TTFT is critical for user experience. Low TTFT feels responsive; high TTFT feels frozen. It''s dominated by prompt encoding time (especially for long contexts), not by generation speed. This is why systems batch prompts separately from generation — you pay encoding cost once per unique prompt, generation cost per output token.', 'TTFT is king for interactive systems. Users notice even 100ms delays.', 'Profile with realistic workloads. Optimize prompt encoding (KV cache reuse, sparse attention). Batch aggressively.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('tokensperscond', 'Tokens per second', '', '', ARRAY['tps','generation speed']::text[], 'Core', 'How many output tokens your inference server produces per second.', 'Words per minute for a typist — measures output speed.', 'Your model generates 50 tokens per second. A 100-token response takes 2 seconds.', '[{"text":"Throughput metric."}]'::jsonb, 'TPS is limited by memory bandwidth (for large models) and compute. Bigger models have higher per-token latency. You increase TPS through batching (process multiple requests together) and parallelization. The tradeoff: batching increases latency per request. You want to batch enough to get good TPS without making individual requests too slow.', 'Throughput scales your revenue. More tokens per dollar means cheaper service.', 'Measure on realistic batch sizes. Profile memory bandwidth. Use pipelining and tensor parallelism.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('batching', 'Batching', '', '', ARRAY['request batching','batch processing']::text[], 'Core', 'Waiting for multiple requests to arrive, then processing them together instead of one at a time.', 'A bus waiting for 30 passengers before leaving, instead of driving immediately with one person.', 'Your inference server holds requests for 100ms. During that time, 32 requests arrive. You process all 32 together.', '[{"text":"Efficiency technique."}]'::jsonb, 'Batching amortizes overhead and uses hardware efficiently. But it increases latency for requests that arrive early in the batch window — they wait for later requests. This is the classic throughput-vs-latency tradeoff. You tune the batch window and max batch size for your workload.', 'Batching makes your hardware work for you. Smaller batches = more serving cost.', 'Implement queue-based batching. Tune max batch size and timeout. Monitor for queue buildup under load.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('continuousbatching', 'Continuous batching', '', '', ARRAY['token-level batching','dynamic batching']::text[], 'Rising', 'Processing multiple requests simultaneously at the token level, starting new requests as old ones finish, without waiting for a batch to fill.', 'A restaurant serving plates as they''re done, instead of waiting for all plates to be ready before serving anyone.', 'Request A is generating token 50 of 100. Request B just arrived. You start processing Request B token 1 while finishing Request A. Once Request A finishes, you start Request C. No idle GPU.', '[{"text":"Advanced serving pattern."}]'::jsonb, 'Continuous batching avoids the latency penalty of traditional batching — you don''t have to wait for a full batch. It also keeps hardware utilized longer. The downside: implementation is complex (need to manage KV caches for varying lengths) and bugs can cause crashes. Systems like vLLM made it practical.', 'Modern standard for serving. Better latency without sacrificing throughput.', 'Use production systems like vLLM. Track KV cache usage. Test overload handling.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('quantization', 'Quantization', '', '', ARRAY['weight quantization','quantized model']::text[], 'Core', 'Converting model weights and activations from high precision (float32) to lower precision (int8, int4) to save memory and speed up computation.', 'Storing a photo in lower resolution to take up less disk space.', 'A model with 7 billion float32 weights uses 28GB of memory. Quantize to int8 (1 byte per weight) and it''s 7GB.', '[{"text":"Key compression technique."}]'::jsonb, 'Quantization trades accuracy for speed and memory. Most of the loss happens in the first few bits; going from float32 to float16 hurts less than float16 to int4. Post-training quantization is easy but less accurate; quantization-aware training is harder but better. Modern quantization methods (GPTQ, AWQ) are surprisingly good.', 'Quantization multiplies your serving capacity. A 7B model that wouldn''t fit on one GPU now fits.', 'Start with int8 post-training quantization. If that''s too lossy, try QAT or mixed-precision.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('int8', 'INT8', '', '', ARRAY['8-bit integer','byte quantization']::text[], 'Core', 'Storing numbers as 8-bit signed integers, allowing values from -128 to 127.', 'A byte — the basic unit of computer memory.', 'Instead of storing a weight as 0.847385 (float32, 4 bytes), store it as 108 (int8, 1 byte).', '[{"text":"Quantization level."}]'::jsonb, 'INT8 is the easiest quantization — it''s hardware-native and most frameworks support it. The tradeoff: 4x memory savings but usually 1-3% accuracy loss. Good for dense models, less good for outlier-heavy models (like transformers).', 'Lowest-hanging fruit for model compression.', 'Use post-training int8 quantization from frameworks. Measure accuracy before deploying.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('int4', 'INT4', '', '', ARRAY['4-bit integer','nibble']::text[], 'Core', 'Storing numbers as 4-bit signed integers, allowing 16 possible values.', 'A nibble — half a byte.', 'Instead of a 1-byte int8 weight, use 4 bits, cramming two weights per byte.', '[{"text":"Aggressive quantization."}]'::jsonb, 'INT4 is aggressive — 8x compression compared to float32. But the accuracy loss is significant unless you do quantization-aware training. Decoding int4 requires unpacking, which can be slower than int8. Used in QLoRA and similar parameter-efficient fine-tuning.', 'Extreme compression for resource-constrained settings.', 'Use with QAT or methods like GPTQ. Monitor for severe accuracy loss.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('fp16', 'FP16', '', '', ARRAY['half precision','float16 format']::text[], 'Core', 'Storing numbers as 16-bit floating-point values, the middle ground between float32 and int8.', 'A reasonable compromise — smaller than float32 but safer than integer quantization.', 'Weight: 0.847385 (float32, 4 bytes) → 0.8474 (float16, 2 bytes).', '[{"text":"Sweet spot for precision."}]'::jsonb, 'FP16 is 2x compression with minimal accuracy loss for most tasks. Modern GPUs (Nvidia A100, H100) are optimized for FP16. Training in FP16 is standard; serving in FP16 is even faster. The downside: FP16 has smaller dynamic range, so some models with very large or very small values suffer.', 'Best balance of compression and safety for most models.', 'Train and serve in FP16 by default. Use FP32 only if you see numerical issues.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('bf16', 'BF16', '', '', ARRAY['brain float','bfloat16 format']::text[], 'Rising', 'A 16-bit floating-point format (from Google Brain) that keeps the same range as float32 but with less precision.', 'A wide-angle lens that captures a larger field of view but at lower pixel density.', 'Float32 can represent 0.0000001 to 1000000000. BF16 can too, but with fewer distinct values in between.', '[{"text":"Improved half-precision."}]'::jsonb, 'BF16 is better than FP16 for training stability because it keeps float32''s range. This matters for transformer training where gradients span many orders of magnitude. It''s becoming standard in recent models (PaLM, Gemini). The downside: less hardware support than FP16 (though Nvidia newer GPUs support it).', 'Emerging standard. Expect more models to use it.', 'Use BF16 for training if your hardware supports it. Performance is similar to FP16 with better stability.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('pruning', 'Pruning', '', '', ARRAY['weight pruning','sparsity']::text[], 'Fading', 'Removing weights from a trained model — setting them to zero — to reduce model size without retraining from scratch.', 'Editing a book by deleting unimportant sentences.', 'A layer has 1 million weights. You remove 50% of them (the ones closest to zero) and the layer still works because those weights didn''t contribute much.', '[{"text":"Compression technique."}]'::jsonb, 'Pruning reduces memory and compute proportionally. Structured pruning (removing whole neurons) is easier to implement but less efficient; unstructured pruning (removing individual weights) is more efficient but requires sparse matrix operations that aren''t always fast on hardware. Modern approach: use sparsity-aware training (pruning during training) instead of post-hoc pruning.', 'Cheaper than retraining but usually less effective than quantization.', 'Start with unstructured magnitude pruning. If hardware doesn''t support sparse ops, use structured pruning instead.', 'Infrastructure & serving', 30, ARRAY['seed','infrastructure-serving']::text[]),
  ('modelcompression', 'Model compression', '', '', ARRAY['compression techniques','model reduction']::text[], 'Core', 'Reducing model size, memory, and/or compute requirements without losing too much performance.', 'Packing more into a suitcase without breaking anything.', 'A 70B model compressed to 13B via distillation, or to 25GB via quantization.', '[{"text":"Umbrella term for efficiency."},{"text":"Quantization is one approach."}]'::jsonb, 'Compression covers multiple techniques: quantization, pruning, distillation, knowledge transfer. Different techniques work for different models and constraints. You might quantize for memory reduction and distill for latency reduction. The key: measure what matters (latency, memory, accuracy) and optimize for all three.', 'Compression unlocks serving at scale. It''s not optional for large models.', 'Profile your bottleneck (memory? latency? compute?). Choose compression technique accordingly.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('gpu', 'GPU', '', '', ARRAY['graphics processing unit','nvidia']::text[], 'Core', 'A specialized processor optimized for parallel computation, essential for training and serving neural networks.', 'A specialized worker who''s really fast at doing lots of simple calculations in parallel.', 'An Nvidia A100 GPU can do trillions of floating-point operations per second, making it 100x faster than a CPU for matrix multiplication.', '[{"text":"The hardware."}]'::jsonb, 'GPUs excel at matrix operations because they have thousands of cores running in parallel. This is perfect for neural networks. The tradeoff: GPUs are expensive ($5k–$20k), use lots of power, and have limited memory (40–80GB for consumer GPUs). Model parallelism, data parallelism, and pipelining are techniques to work around these limits.', 'GPU cost dominates the serving budget for large models.', 'Profile your model. Estimate memory (parameters × bytes per param). Choose GPU based on memory and latency needs.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('tpu', 'TPU', '', '', ARRAY['tensor processing unit','google tpu']::text[], 'Core', 'Google''s custom-built processor for tensor operations, competitive with GPUs for training and serving.', 'An even more specialized worker designed just for neural network math.', 'A TPU v4 pod has 256 TPU chips connected with ultra-fast networking, used to train Gemini.', '[{"text":"Alternative to GPUs."}]'::jsonb, 'TPUs are purpose-built for the exact operations neural networks need. They''re very fast and power-efficient. The downside: they''re only available on Google Cloud, less software support than GPUs, and harder to debug. Good for training large models, fine-tuning is usually cheaper on GPUs.', 'Cost-effective for training at Google scale. Harder to use for serving individual requests.', 'Consider TPUs if you''re training a really large model. Expect learning curve.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('vram', 'VRAM', '', '', ARRAY['gpu memory','video memory']::text[], 'Core', 'The memory on a GPU, where model weights, activations, and intermediate results live during computation.', 'The scratch pad a calculator uses to store partial results.', 'A 7B model in BF16 needs 14GB VRAM. Batch size 32 and intermediate computations might need another 20GB. Total: 34GB VRAM.', '[{"text":"Scarce resource."}]'::jsonb, 'VRAM is the bottleneck for most large model serving. You can''t fit the model if VRAM < model size + activation memory. This is why quantization and model parallelism exist. Estimating VRAM usage correctly is critical — underestimate and you get OOM errors; overestimate and you buy GPUs you don''t need.', 'VRAM cost is your serving cost. Every bit of memory reduction matters.', 'Estimate: params × bytes per param + (batch × seq_len × hidden × factor) for activations. Test before deploying.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('cuda', 'CUDA', '', '', ARRAY['gpu programming','cuda kernels']::text[], 'Core', 'Nvidia''s parallel computing platform that lets you write programs that run on GPUs.', 'A programming language specifically designed to talk to your GPU.', 'You write a CUDA kernel that processes 1000 samples in parallel. Each GPU core handles one sample simultaneously.', '[{"text":"Low-level GPU programming."},{"text":"What ML frameworks use."}]'::jsonb, 'CUDA is how researchers and engineers squeeze extra performance from GPUs. Writing optimized CUDA is hard (you have to manage thread blocks, memory hierarchies, and synchronization), but it can be 10x faster than unoptimized code. Most ML frameworks (PyTorch, JAX) use CUDA under the hood.', 'Framework choice often determines CUDA optimization. More mature frameworks = better CUDA kernels.', 'Usually you don''t write CUDA directly. Use frameworks that have well-optimized kernels. Profile with nvprof.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('accelerator', 'Accelerator', '', '', ARRAY['hardware accelerator','specialized chip']::text[], 'Rising', 'A specialized piece of hardware (GPU, TPU, IPU, etc.) optimized for specific computations like neural networks.', 'A specialized tool for a specific job — like a pasta maker, not a general-purpose knife.', 'AWS Trainium for training, Inferentia for inference, Nvidia H100 for both.', '[{"text":"Hardware trends."}]'::jsonb, 'Accelerators are faster and more power-efficient than CPUs for their specific task. But they''re expensive, hard to program, and inflexible — if you need a different computation, a CPU might be simpler. The trend is toward domain-specific accelerators (for LLMs, vision, etc.) instead of general-purpose GPUs.', 'Accelerator choice affects cost, speed, and lock-in. Choose wisely.', 'Profile your workload (compute pattern, memory bandwidth). Choose accelerator that matches it.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('cluster', 'Cluster', '', '', ARRAY['gpu cluster','distributed compute']::text[], 'Core', 'A group of computers connected by a network, working together to run a single large job.', 'A team of workers instead of one person — they can tackle bigger jobs by dividing work.', 'A training cluster for a 70B model: 256 GPUs across 64 servers, connected with fast networking.', '[{"text":"How to scale beyond one machine."}]'::jsonb, 'Clusters let you train or serve models too large for a single machine. The networking between machines becomes a bottleneck — slow networking kills scaling efficiency. This is why distributed training frameworks optimize for communication. Large clusters are expensive (especially the networking) and hard to debug.', 'Cluster cost scales with model size. Know your break-even point.', 'Use distributed training frameworks (PyTorch DDP, DeepSpeed). Profile communication overhead. Invest in fast networking.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('node', 'Node', '', '', ARRAY['compute node','server instance']::text[], 'Core', 'A single computer in a cluster, usually with a GPU and some CPU cores.', 'One person on a team.', 'A node: one server with 8 Nvidia H100 GPUs, 256GB CPU RAM, 2TB NVMe storage.', '[{"text":"Cluster building block."}]'::jsonb, 'A node is the unit you allocate for jobs. Small nodes (1 GPU) are good for inference; large nodes (8+ GPUs) are good for training. You pay per node, per hour. Sharing nodes between jobs is complex (resource contention, debugging) so most clusters run one job per node.', 'Node cost is your primary budget unit. Know how many you need.', 'Understand your cluster''s node config. Profile your job''s resource usage per node.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('apiserver', 'API', '', '', ARRAY['rest api','inference endpoint']::text[], 'Core', 'A web interface that lets users send requests to your model and get responses back.', 'A restaurant''s delivery app — you place an order, they fulfill it.', 'OpenAI''s API: you POST {"model":"gpt-4","messages":[...]} and get back a response.', '[{"text":"How models reach users."}]'::jsonb, 'APIs hide complexity. Users don''t care how you''re serving (GPU, TPU, quantized, distilled). Your job: take requests, run inference, return results. Challenges: rate limiting, billing, reliability, latency SLOs, and preventing abuse (token limits, content filters, cost caps).', 'APIs are how you monetize models. Design for scalability and robustness.', 'Use async frameworks (FastAPI, Gunicorn). Implement request queuing, caching, monitoring. Plan for scaling.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[])
